# capacity/limit_analysis.py
from dataclasses import dataclass

@dataclass
class RateLimitSet:
    rpm_limit: int
    tpm_limit: int
    tpd_limit: int

@dataclass
class IntegrationLoad:
    peak_rps: float               # requests per second at peak
    avg_tokens_per_request: int   # input + output tokens
    daily_hours_active: float     # how many hours per day is peak sustained

    @property
    def peak_rpm(self) -> float:
        return self.peak_rps * 60

    @property
    def peak_tpm(self) -> int:
        return int(self.peak_rpm * self.avg_tokens_per_request)

    @property
    def daily_tokens(self) -> int:
        return int(self.peak_tpm * 60 * self.daily_hours_active)

def analyse_headroom(load: IntegrationLoad, limits: RateLimitSet) -> dict:
    return {
        "rpm_utilisation": load.peak_rpm / limits.rpm_limit,
        "tpm_utilisation": load.peak_tpm / limits.tpm_limit,
        "tpd_utilisation": load.daily_tokens / limits.tpd_limit,
        "binding_constraint": max(
            ("RPM", load.peak_rpm / limits.rpm_limit),
            ("TPM", load.peak_tpm / limits.tpm_limit),
            ("TPD", load.daily_tokens / limits.tpd_limit),
            key=lambda x: x[1],
        )[0],
    }

# Example: customer support RAG
load = IntegrationLoad(peak_rps=20.0, avg_tokens_per_request=2_800, daily_hours_active=8)
limits = RateLimitSet(rpm_limit=5_000, tpm_limit=5_000_000, tpd_limit=100_000_000)
result = analyse_headroom(load, limits)
print(result)
# {'rpm_utilisation': 0.24, 'tpm_utilisation': 0.672, 'tpd_utilisation': 0.269,
#  'binding_constraint': 'TPM'}

# client/rate_limit_reader.py
from dataclasses import dataclass
from typing import Optional
import httpx

@dataclass
class RateLimitSnapshot:
    limit_rpm: int
    remaining_rpm: int
    limit_tpm: int
    remaining_tpm: int
    reset_at_ms: Optional[int]   # milliseconds until window resets

    @property
    def rpm_headroom_pct(self) -> float:
        return self.remaining_rpm / self.limit_rpm if self.limit_rpm else 1.0

    @property
    def tpm_headroom_pct(self) -> float:
        return self.remaining_tpm / self.limit_tpm if self.limit_tpm else 1.0

    @property
    def is_near_limit(self) -> bool:
        return self.rpm_headroom_pct < 0.20 or self.tpm_headroom_pct < 0.20

def extract_rate_limits(response: httpx.Response) -> Optional[RateLimitSnapshot]:
    h = response.headers
    try:
        return RateLimitSnapshot(
            limit_rpm=int(h.get("x-ratelimit-limit-requests", 0)),
            remaining_rpm=int(h.get("x-ratelimit-remaining-requests", 0)),
            limit_tpm=int(h.get("x-ratelimit-limit-tokens", 0)),
            remaining_tpm=int(h.get("x-ratelimit-remaining-tokens", 0)),
            reset_at_ms=int(h["x-ratelimit-reset-tokens"].rstrip("s")) * 1000
                if "x-ratelimit-reset-tokens" in h else None,
        )
    except (KeyError, ValueError):
        return None

# client/retry_policy.py
import time
import random
import logging
import anthropic

class RateLimitRetryPolicy:
    def __init__(
        self,
        max_retries: int = 4,
        base_delay_s: float = 1.0,
        max_delay_s: float = 60.0,
        jitter_factor: float = 0.2,
    ):
        self.max_retries = max_retries
        self.base_delay_s = base_delay_s
        self.max_delay_s = max_delay_s
        self.jitter_factor = jitter_factor

    def delay_for_attempt(self, attempt: int, retry_after_s: float = 0) -> float:
        # Exponential backoff: base * 2^attempt, capped at max_delay
        backoff = min(self.base_delay_s * (2 ** attempt), self.max_delay_s)
        # Use the larger of backoff and Retry-After
        wait = max(backoff, retry_after_s)
        # Add jitter: ±jitter_factor fraction of the wait time
        jitter = wait * self.jitter_factor * (2 * random.random() - 1)
        return max(0, wait + jitter)

    def call_with_retry(self, client: anthropic.Anthropic, **kwargs) -> anthropic.types.Message:
        for attempt in range(self.max_retries + 1):
            try:
                return client.messages.create(**kwargs)
            except anthropic.RateLimitError as e:
                if attempt == self.max_retries:
                    raise
                retry_after = float(getattr(e, "retry_after", 0) or 0)
                delay = self.delay_for_attempt(attempt, retry_after)
                logging.warning(
                    "Rate limited (attempt %d/%d), retrying in %.1fs",
                    attempt + 1, self.max_retries, delay,
                )
                time.sleep(delay)
            except anthropic.APIStatusError as e:
                if e.status_code >= 500 and attempt < self.max_retries:
                    delay = self.delay_for_attempt(attempt)
                    logging.warning(
                        "Server error %d (attempt %d/%d), retrying in %.1fs",
                        e.status_code, attempt + 1, self.max_retries, delay,
                    )
                    time.sleep(delay)
                else:
                    raise
        raise RuntimeError("Unreachable")

# capacity/concurrency_model.py
from dataclasses import dataclass
import math

@dataclass
class ConcurrencyModel:
    max_concurrent_requests: int
    avg_tokens_per_request: int       # input + output
    avg_request_duration_s: float     # wall-clock time per request

    @property
    def requests_per_minute(self) -> float:
        # How many requests complete per minute at max concurrency
        return (self.max_concurrent_requests / self.avg_request_duration_s) * 60

    @property
    def peak_tpm(self) -> int:
        # Tokens per minute at max concurrency
        # The entire token count of each request lands in the 60s window
        # when the request starts — not when it completes
        return int(self.requests_per_minute * self.avg_tokens_per_request)

    def safe_concurrency_for_tpm_limit(self, tpm_limit: int, target_utilisation: float = 0.70) -> int:
        allowed_tpm = int(tpm_limit * target_utilisation)
        allowed_rpm = allowed_tpm / self.avg_tokens_per_request
        return math.floor(allowed_rpm * self.avg_request_duration_s / 60)

# Batch processing worker pool
model = ConcurrencyModel(
    max_concurrent_requests=20,
    avg_tokens_per_request=5_000,
    avg_request_duration_s=8.0,
)
print(f"Peak TPM at 20 workers: {model.peak_tpm:,}")  # 750,000

# How many workers can run within 5M TPM at 70% utilisation?
safe = model.safe_concurrency_for_tpm_limit(tpm_limit=5_000_000)
print(f"Safe workers for 5M TPM: {safe}")  # 46

# capacity/worker_sizer.py
import math
from dataclasses import dataclass

@dataclass
class WorkerPoolConfig:
    tpm_limit: int
    avg_input_tokens: int
    avg_output_tokens: int
    avg_request_duration_s: float
    target_utilisation: float = 0.70

    @property
    def avg_tokens_per_request(self) -> int:
        return self.avg_input_tokens + self.avg_output_tokens

    @property
    def max_tpm_budget(self) -> int:
        return int(self.tpm_limit * self.target_utilisation)

    @property
    def max_rpm_budget(self) -> float:
        return self.max_tpm_budget / self.avg_tokens_per_request

    @property
    def optimal_worker_count(self) -> int:
        # Workers = RPM budget * avg_duration / 60
        # (Little's Law: N = λ * W, where λ=rpm/60 and W=duration_s)
        return max(1, math.floor(self.max_rpm_budget * self.avg_request_duration_s / 60))

    @property
    def throughput_per_hour(self) -> int:
        requests_per_minute = self.optimal_worker_count * 60 / self.avg_request_duration_s
        return int(requests_per_minute * 60)

config = WorkerPoolConfig(
    tpm_limit=5_000_000,
    avg_input_tokens=4_000,
    avg_output_tokens=800,
    avg_request_duration_s=10.0,
)
print(f"Optimal workers: {config.optimal_worker_count}")  # 17
print(f"Throughput: {config.throughput_per_hour:,} requests/hour")  # 6,120

