from dataclasses import dataclass

@dataclass
class UpgradeRequest:
    integration_name: str
    current_tpm_limit: int
    current_p95_tpm: int
    projected_p95_tpm_90d: int
    integrations_on_key: list[str]

    @property
    def current_utilisation(self) -> float:
        return self.current_p95_tpm / self.current_tpm_limit

    @property
    def required_tpm_limit(self) -> int:
        # Required limit so that projected P95 is at 70% utilisation
        return int(self.projected_p95_tpm_90d / 0.70)

    def summary(self) -> str:
        return (
            f"Upgrade Request — {self.integration_name}\n"
            f"  Current limit:     {self.current_tpm_limit:>12,} TPM\n"
            f"  Current P95 usage: {self.current_p95_tpm:>12,} TPM "
            f"({self.current_utilisation:.1%} utilisation)\n"
            f"  Projected P95 (90d): {self.projected_p95_tpm_90d:>10,} TPM\n"
            f"  Required limit:    {self.required_tpm_limit:>12,} TPM\n"
            f"  Shared by: {', '.join(self.integrations_on_key)}\n"
        )
